var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"뭐야, 무슨 일로 날 부른 거지?","JPN":"何、なんの用で私を呼び出したのかしら？","ENG":"Huh? What did you want to see me for?","TWN":"幹嘛？找我有什麼事？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"후후, 승부라면 얼마든지 환영인 게야. 물론, 내가 또 이기겠지만 말이지.","JPN":"ふふ、勝負ならいつでも歓迎するわ。もちろん、また私が勝つだろうけど。","ENG":"Fu fu, You want to go another round with me? Of course, I'll be the winner in the end.","TWN":"呵呵，要找我賭一盤的話當然歡迎，不過結局當然是我贏。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"잠깐. 생각해보니 뭔가 이상하군.","JPN":"待って。考えてみたら何か変よね。","ENG":"Wait. Come to think of it, something's weird.","TWN":"等等，仔細想想，好像不太對勁。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"자네는 어째서 이기지도 못할 승부를 계속 걸어오는 게지?","JPN":"あんた、どうして勝てない勝負を次々かけてくるの？","ENG":"Why do you keep challenging me even though you know you can't win?","TWN":"明知會輸，為什麼你還是一直來找我賭呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"으, 으응? 그냥 내가 이겨서 좋아하는 모습이 보고 싶었을 뿐이라고?","JPN":"え、ええ？　ただ私が勝って喜ぶ姿が見たかっただけだって？","ENG":"H-huh? You just wanted to see my being happy when I win?","TWN":"什…什麼？你只是想看我賭贏後很開心的樣子？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"당신 뭐야! 무슨 꿍꿍이야!?","JPN":"あんたって何！　何のつもり！？","ENG":"What's your angle, huh?!","TWN":"你幹嘛！在打什麼歪主意！？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"지금껏 목숨을 걸고 갬블에서 이겨온 내가 그딴 말을 쉽게 믿을 것 같아!?","JPN":"今まで命をかけてギャンブルで勝ってきた私が、そんな言葉を信じるとでも思う！？","ENG":"I've made it all the way here by gambling with my life. Do you really think I'm going to fall for that?!","TWN":"我在賭界打滾那麼久，你以為我會輕易相信那種話嗎！？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"그러고 보니…… 처음부터 수상했어. 어째서 나 같은걸…….","JPN":"そうえいば……最初から怪しかったわ。何で私みたいなのを……","ENG":"But now that I think of it... I knew something was up. Why else would you bother with someone like me...?","TWN":"現在回想起來……打從一開始就事有蹊蹺，怎麼會對我這種……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"대답해. 당신, 왜 내게 접근한 거지?","JPN":"答えて。あんた、なんで私に近づいてきたの？","ENG":"Hey, answer me. Why did you approach me in the first place?","TWN":"快說！你為何要接近我？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"내 돈을 원하는 거야? 아니면 내 기술력? 그것도 아니라면…… 설마……. 그 아이?","JPN":"私のお金が欲しくて？　それとも技術力？　でなければ……まさか……あの子？","ENG":"Are you after my money? Or my technique? If that's not it... then could it be... that child?","TWN":"是想要我的錢嗎？還是我的棋藝？還是……該不會是……那個孩子？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"저, 정말로 그냥 체스 상대를 원할 뿐이라고……?","JPN":"ほ、本当にただチェス相手がほしいだけですって……？","ENG":"Y-you really just wanted someone to play Chess with...?","TWN":"你…你真的只是想找個可以下棋的對象……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"후후…… 후하하하! 대체 누가 그런 말을 믿겠냐고……! 이기지도 못하는 주제에…….","JPN":"ふふ……はははは！　いったい誰がそれを信じるの……！　勝てもしないくせに……","ENG":"Fu fu... Hahahaha! Who would be foolish enough to believe that? You can't even win...","TWN":"哈哈……哈哈哈哈！這種話到底誰會信……！更何況你還每次都輸……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"좋아. 그럼, 승부하자.","JPN":"いいわ、それじゃ勝負しよう。","ENG":"All right then. Let's play.","TWN":"好，那來下一盤吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"내가 이기면…… 당신 목적이 뭔지, 나에 대해 얼마나 알고 있는지 낱낱이 말해줘야겠어","JPN":"私が勝ったら……あんたの目的が何なのか、私についてどのくらい知っているか全部話してもらう。","ENG":"If I win... you have to tell me everything you know about me and what you're planning to do.","TWN":"我贏的話……就把你的目的，還有你到底知道我多少事情，一五一十地說出來！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"그리고 당신이 이긴다면…… 특별히 거기 있는 종이 쪼가리에 서명해주지, 어때?","JPN":"そしてあんたが勝ったら……特別にそこにある紙切れにサインしてあげる、どう？","ENG":"But if you win... Then I'll gladly sign that piece of paper. Sound fair?","TWN":"要是你贏的話……我就同意在那張破紙上簽名，怎麼樣？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHESS_ALPHA_NULL_NULL","text":{"KOREA":"……뭐, 뭐어! 어차피 내가 이기겠지만!","JPN":"……ま、まあ！　どうせ私が勝つだろうけど！","ENG":"...W-whatever the case...! It'll be me who gets the last laugh!","TWN":"……反…反正！一定是我贏！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHESS_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};